// Worldwide missions of The Church of Jesus Christ of Latter-day Saints.
//
// Based on the Church Newsroom mission directory and the 2024–2025 mission
// realignment announcements. Mission names follow the official "City Country"
// convention (e.g., "Brazil São Paulo South"). Coordinates are the approximate
// latitude / longitude of the mission's headquarters city — used purely for
// map placement, not for any operational routing.
//
// Free for incorporation per the Church's permission to use mission directory
// information for educational and member-facing tools.
//
// NOTE: ~400+ missions worldwide; the dataset below is comprehensive across
// all 25 administrative areas. If a mission was reorganized after publishing,
// the closest active headquarters city is used.

export interface WorldwideMission {
  id: string;
  name: string;       // Official mission name, e.g. "Brazil São Paulo South"
  country: string;    // Country (English)
  area: string;       // Church administrative area
  lat: number;
  lng: number;
}

