export function findMissionById(id: string | null | undefined): WorldwideMission | null {
  if (!id) return null;
  return WORLDWIDE_MISSIONS.find((m) => m.id === id) ?? null;
}

// Group by area for area-grouped pickers.
export function getMissionsByArea(): Record<string, WorldwideMission[]> {
  const groups: Record<string, WorldwideMission[]> = {};
  for (const m of WORLDWIDE_MISSIONS) {
    (groups[m.area] ||= []).push(m);
  }
  for (const key of Object.keys(groups)) {
    groups[key].sort((a, b) => a.name.localeCompare(b.name));
  }
  return groups;
}

